// 1. Extrai o conteúdo bruto (navegando pela estrutura complexa do payload)
const output = $json.output?.[0] || {};
const content = output.content?.[0] || {};
const raw = content.text || {};

let parsed;

// 2. Trata se o 'text' vier como String ou Objeto
if (typeof raw === "string") {
  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    parsed = { scenes: [] };
  }
} else {
  parsed = raw;
}

// 3. Garante que scenes seja um array
let scenes = Array.isArray(parsed.scenes) ? parsed.scenes : [];

// 4. A MÁGICA: Localiza a última cena e altera o type
if (scenes.length > 0) {
  const lastIndex = scenes.length - 1;
  scenes[lastIndex].type = "vinheta";
}

// 5. Retorna o objeto formatado para o n8n
return [
  {
    json: {
      scenes
    }
  }
];

const srtRaw = $json.data;

if (!srtRaw) {
  throw new Error("SRT content not found");
}

// Função para converter HH:MM:SS,mmm → segundos
function timeToSeconds(time) {
  const [hms, ms] = time.split(",");
  const [h, m, s] = hms.split(":").map(Number);

  return h * 3600 + m * 60 + s + Number(ms) / 1000;
}

// Divide blocos por linhas vazias
const blocks = srtRaw.trim().split("\n\n");

const parsed = blocks.map(block => {
  const lines = block.split("\n");

  const index = Number(lines[0]);
  const [startRaw, endRaw] = lines[1].split(" --> ");

  const text = lines.slice(2).join(" ").trim();

  const start = timeToSeconds(startRaw);
  const end = timeToSeconds(endRaw);

  return {
    index,
    start,
    end,
    duration: +(end - start).toFixed(3),
    text
  };
});

// Duração total do vídeo
const totalDuration = parsed.length
  ? parsed[parsed.length - 1].end
  : 0;

return [
  {
    json: {
      totalDuration,
      subtitles: parsed
    }
  }
];

// Pega a scene do item atual
const scene = $json.scenes || {};

// =============================
// 1️⃣ NORMALIZAÇÃO DE TEMPO
// =============================
const subtitles = scene.subtitles || [];
const start = subtitles.length ? Number(subtitles[0].start) : 0;
const end = subtitles.length
  ? Number(subtitles[subtitles.length - 1].end)
  : start;
const duration = +(end - start).toFixed(3);

// =============================
// 2️⃣ SANITIZAÇÃO DO VISUAL
// =============================
let visual = scene.visual || "";
visual = visual.replace(/'[^']*'/g, "");
visual = visual.replace(
  /labeled|label|signs?|text|written|words?|typography|letters?|numbers?/gi,
  ""
);
visual = visual.replace(/\s+/g, " ").trim();

// =============================
// 3️⃣ CONTEXTO SEMÂNTICO
// =============================
const emotion = scene.emotion || "";
const keywords = Array.isArray(scene.keywords) ? scene.keywords.join(", ") : "";

// =============================
// 4️⃣ BASE STYLE GLOBAL
// =============================
const baseStyle = `
vertical 9:16
no text
no letters
no words
no watermark
no logo
`;

// =============================
// 5️⃣ PROMPT FINAL OTIMIZADO
// =============================
const prompt = `
${visual},

emotion: ${emotion},
context: ${keywords},

${baseStyle}
`.trim();

// =============================
// 6️⃣ OUTPUT FINAL
// =============================
return {
  json: {
    scene: scene.scene ?? null,
    start,
    end,
    duration,
    visual: scene.visual ?? "",
    emotion,
    keywords: scene.keywords || [],
    prompt,
    type:scene.type
  }
};

return items.map((item) => {
  const base64 = item.json.artifacts[0].base64;

  const scene = item.json.scene;
  const emotion = item.json.emotion || "scene";
  const start = item.json.start;
  const duration = item.json.duration;

  return {
    json: {
      scene,
      start,
      duration,
      emotion,
      prompt: item.json.prompt
    },
    binary: {
      image: {
        data: base64,
        mimeType: "image/png",
        fileName: `scene_${scene}.png`
      }
    }
  };
});

return items.map((item, i) => {
  const base = {
    index: i, // index sequencial
    scene: item.json.scene,
    start: item.json.start,
    end: item.json.end  ,
    duration: item.json.duration,
    source: item.json.source || "ai",
    meta: {
      emotion: item.json.emotion,
      prompt: item.json.prompt
    },
    asset: {
      type: "image",
      // para stock ou binary, src será ajustado abaixo
      src: item.json.asset?.src || item.json.src || ""
    },
    motion: item.json.asset?.motion || { from: 1, to: 1, style: "none" } // garante motion padrão se não houver
  };

  // Se for IA (tem binary)
  if (item.binary && item.binary.image) {
    return {
      json: {
        ...base,
        asset: {
          ...base.asset,
          src: "binary://image"
        }
      },
      binary: item.binary
    };
  }

  // Se for stock
  return { json: base };
});

function getMotionByEmotion(emotion) {
  switch (emotion) {
    case "urgency":
      return { style: "zoom", from: 1.0, to: 1.15 };

    case "curiosity":
      return { style: "pan", direction: "left", intensity: 0.15 };

    case "motivation":
      return { style: "zoom", from: 1.0, to: 1.08 };

    case "shock":
      return { style: "zoom", from: 1.0, to: 1.2 };

    case "inspiration":
      return { style: "pan", direction: "right", intensity: 0.12 };

    default:
      return null;
  }
}

// Motion aleatório seguro
function getRandomMotion() {
  const styles = ["zoom", "panLeft", "panRight", "zoomPan", "shake"];
  const style = styles[Math.floor(Math.random() * styles.length)];

  switch (style) {
    case "zoom":
      return {
        style: "zoom",
        from: 1.0,
        to: 1.1 + Math.random() * 0.1
      };

    case "panLeft":
      return {
        style: "pan",
        direction: "left",
        intensity: 0.05 + Math.random() * 0.15
      };

    case "panRight":
      return {
        style: "pan",
        direction: "right",
        intensity: 0.05 + Math.random() * 0.15
      };

    case "zoomPan":
      return {
        style: "zoom",
        from: 1.0,
        to: 1.08 + Math.random() * 0.12
      };



    default:
      return {
        style: "zoom",
        from: 1.0,
        to: 1.1
      };
  }
}

// Aplicação
return items.map((item, i) => {

  const isLastScene = i === items.length - 1;

  const emotion = item.json.emotion;

  // 👇 sem motion na última cena (vinheta)
  const motion = isLastScene
    ? null
    : (getMotionByEmotion(emotion) || getRandomMotion());

  return {
    json: {
      index: i,

      scene: item.json.scene,

      start: item.json.start,

      duration: item.json.duration,
      end: item.json.end,
      asset: {
        type: "image",
        src: item.json.scene_path,
        motion: motion // será null na vinheta
      },

      source: "ai",

      isVinheta: isLastScene // 👈 MUITO IMPORTANTE pro render.js
    }
  };
});

function sanitizeFileName(name) {
  return name
    .normalize("NFD") // separa acentos
    .replace(/[\u0300-\u036f]/g, "") // remove acentos
    .replace(/\./g, "") // remove pontos
    .replace(/\s+/g, "_") // espaços -> _
    .replace(/[^a-zA-Z0-9_-]/g, "") // remove caracteres estranhos
    .toLowerCase();
}

return items.map((item) => {
  const base64 = item.json.artifacts[0].base64;

  const visual = item.json.visual;
  const nicho = $('Limit').first().json.nicho
  const safeName = sanitizeFileName(visual);

  return {
    json: {
      visual,
      nicho
    },
    binary: {
      image: {
        data: base64,
        mimeType: "image/png",
        fileName: `${safeName}.png`
      }
    }
  };
});
